p.m:
\displaystyle{\begin{aligned}
   16\div \frac{4}{3} 
       \amp = \frac{16}{1} \div \frac{4}{3} \\
       \amp = \frac{16}{1} \cdot \frac{3}{4} \amp \hbox{We can divide 16 and 4 by 4 and made those two values smaller.}\\
       \amp = \frac{4}{1}\cdot\frac{3}{1} \\
       \amp = \frac{4\cdot3}{1 \cdot 1} \\
       \amp = 12
\end{aligned}
    }
